import ReactMarkdown from 'react-markdown'
import GeneralArticles from '../components/GeneralArticles'
import TechnicalArticles from '../components/TechnicalArticles'
import Projects from '../components/Projects'
import Artworks from '../components/Artworks'
import Simulations from '../components/Simulations'
import Animations from '../components/Animations'

const Index = ({content}) => {
    console.log(content)
  return (
    <>
      <style>{styles}</style>
      <div className="page-wrapper">
        <div className='introduction'>
            <ReactMarkdown source={content.default} />
        </div>
        <div style={{ display:'flex', flexDirection:'row' }}>
          <div>

          </div>
          <div>

          </div>
        </div>
        <GeneralArticles/>
        <TechnicalArticles/>
        <Projects/>
        <Artworks/>
        <Simulations/>
        <Animations/>
      </div>
    </>
  );
};

Index.getInitialProps = async ctx => {
    const content = await require(`../markdown/introduction.md`)
    return { content }
}

const styles = `
    .page-wrapper {
        width:80vw;
        margin:auto;
        font-family:Roboto;
    }
`;

export default Index;
